import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title TokenVesting
 * @dev A token vesting contract for team allocations with cliff and linear vesting.
 */
contract TokenVesting is AccessControl, Pausable, ReentrancyGuard {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");
    bytes32 public constant VESTING_MANAGER_ROLE = keccak256("VESTING_MANAGER_ROLE");

    struct VestingSchedule {
        address beneficiary;
        uint256 totalAmount;
        uint256 startTime;
        uint256 cliffDuration;
        uint256 duration;
        uint256 releasedAmount;
        bool revocable;
        bool revoked;
    }

    mapping(address => VestingSchedule[]) public vestingSchedules;
    mapping(address => uint256) public vestingCount;

    event VestingCreated(address indexed beneficiary, uint256 amount, uint256 startTime, uint256 cliffDuration, uint256 duration);
    event VestingReleased(address indexed beneficiary, uint256 amount);
    event VestingRevoked(address indexed beneficiary, uint256 unvestedAmount);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(PAUSER_ROLE, msg.sender);
        _grantRole(VESTING_MANAGER_ROLE, msg.sender);
    }

    function createVesting(
        address beneficiary,
        uint256 totalAmount,
        uint256 startTime,
        uint256 cliffDuration,
        uint256 duration,
        bool revocable
    ) external onlyRole(VESTING_MANAGER_ROLE) whenNotPaused {
        require(beneficiary != address(0), "Beneficiary is zero address");
        require(totalAmount > 0, "Total amount is zero");
        require(duration > 0, "Duration is zero");
        require(cliffDuration <= duration, "Cliff exceeds duration");

        uint256 scheduleId = vestingCount[beneficiary];
        vestingSchedules[beneficiary].push(VestingSchedule({
            beneficiary: beneficiary,
            totalAmount: totalAmount,
            startTime: startTime,
            cliffDuration: cliffDuration,
            duration: duration,
            releasedAmount: 0,
            revocable: revocable,
            cliffDuration: 0,
            duration: 0,
            revoked: false
        }));
        vestingCount[beneficiary]++;

        emit VestingCreated(beneficiary, totalAmount, startTime, cliffDuration, duration);
    }

    function release(address beneficiary, uint256 scheduleId) external nonReentrant whenNotPaused {
        VestingSchedule storage schedule = vestingSchedules[beneficiary][scheduleId];
        require(schedule.beneficiary == msg.sender || hasRole(DEFAULT_ADMIN_ROLE, msg.sender), "Not authorized");
        require(!schedule.revoked, "Vesting revoked");
        require(schedule.startTime > 0, "Vesting not started");

        uint256 vestedAmount = computeVestedAmount(schedule);
        uint256 releasableAmount = vestedAmount - schedule.releasedAmount;

        require(releasableAmount > 0, "No tokens to release");

        schedule.releasedAmount += releasableAmount;
        IERC20(token).transfer(schedule.beneficiary, releasableAmount);

        emit VestingReleased(beneficiary, releasableAmount);
    }

    function computeVestedAmount(VestingSchedule storage schedule) internal view returns (uint256) {
        if (block.timestamp < schedule.startTime + schedule.cliffDuration) {
            return 0;
        }
        if (block.timestamp >= schedule.startTime + schedule.duration) {
            return schedule.totalAmount;
        }
        uint256 timeFromStart = block.timestamp - schedule.startTime;
        return (schedule.totalAmount * timeFromStart) / schedule.duration;
    }

    function revokeVesting(address beneficiary, uint256 scheduleId) external onlyRole(VESTING_MANAGER_ROLE) {
        VestingSchedule storage schedule = vestingSchedules[beneficiary][scheduleId];
        require(schedule.revocable, "Not revocable");
        require(!schedule.revoked, "Already revoked");

        uint256 vestedAmount = computeVestedAmount(schedule);
        uint256 unvestedAmount = schedule.totalAmount - vestedAmount;

        schedule.revoked = true;

